solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string code;
        std::cin >> code;
        if (code == "A" || code == "C") {
            std::cout << code << ": Procedural\n";
        } else {
            std::cout << code << ": OOP\n";
        }
    }
    return 0;
}

