solution_code:
#include <iostream>

struct Score {
    int value;
};

void addPoints(Score& s, int pts) {
    s.value += pts;
}

int main() {
    Score s;
    s.value = 0;
    addPoints(s, 10);
    addPoints(s, 5);
    std::cout << "Final score: " << s.value << "\n";
    return 0;
}
